import (
	"context"
	"fmt"
	"time"

	"github.com/dop251/goja"
)

const (
	// scriptTimeout is the maximum time allowed for a discount script to run.
	scriptTimeout = 2 * time.Second
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with order fields injected as global variables, and returns the resulting discount amount.
// A timeout is enforced to prevent runaway scripts.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	// Create a context with a deadline to limit execution time.
	ctx, cancel := context.WithTimeout(context.Background(), scriptTimeout)
	defer cancel()

	// Create a new VM.
	vm := goja.New()

	// Inject context as a global variable for timeout checking.
	vm.Set("context", ctx)

	// Inject order fields as global variables.
	for k, v := range order {
		vm.Set(k, v)
	}

	// Run the script.
	result, err := vm.RunString(script)
	if err != nil {
		// Differentiate between a timeout and a regular script error.
		if ctx.Err() == context.DeadlineExceeded {
			return 0.0, fmt.Errorf("script execution timed out after %v: %w", scriptTimeout, ctx.Err())
		}
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Convert the result to a float64 discount.
	discount, ok := result.Export().(float64)
	if !ok {
		// Handle other numeric types that JavaScript might return.
		switch v := result.Export().(type) {
		case int:
			discount = float64(v)
		case int32:
			discount = float64(v)
		case int64:
			discount = float64(v)
		case float32:
			discount = float64(v)
		default:
			return 0.0, fmt.Errorf("script must return a number, got %T", result.Export())
		}
	}

	// Ensure the discount is not negative.
	if discount < 0 {
		return 0.0, fmt.Errorf("discount must be non‑negative, got %f", discount)
	}

	// Optional: verify the discount does not exceed the order total if present.
	if total, ok := order["total"].(float64); ok {
		if discount > total {
			return 0.0, fmt.Errorf("discount %f exceeds order total %f", discount, total)
		}
	}

	return discount, nil
}

