// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with order fields injected as global variables, and returns the resulting discount amount.
// Security improvements:
// 1. Adds timeout to prevent DoS attacks (infinite loops)
// 2. Restricts access to dangerous JavaScript built-ins (Promise, etc.)
// 3. Limits execution time to prevent resource exhaustion
// 4. Validates discount output is non-negative
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	// Create a context with timeout to prevent DoS attacks from infinite loops
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	vm := goja.New()

	// Start a goroutine to interrupt the VM when context is cancelled
	go func() {
		select {
		case <-ctx.Done():
			vm.Interrupt(ctx.Err())
		}
	}()

	// Restrict dangerous JavaScript built-ins by setting them to undefined
	// This prevents scripts from accessing Promise, Symbol, and other potentially dangerous constructors
	restrictedGlobals := []string{
		"Promise", "Symbol", "Proxy", "Reflect", "WeakMap", "WeakSet",
		"BigInt", "BigInt64Array", "Float64Array", "Float32Array",
		"Int32Array", "Int16Array", "Int8Array", "Uint32Array",
		"Uint16Array", "Uint8Array", "Uint8ClampedArray",
		"DataView", "ArrayBuffer", "SharedArrayBuffer",
