// sanitizeIdentifier ensures that a map key can be used as a JavaScript identifier.
// It replaces any character that is not a letter, digit, '_' or '$' with '_',
// and makes sure the identifier does not start with a digit.
func sanitizeIdentifier(name string) string {
	if len(name) == 0 {
		return "_"
	}
	var res []rune
	for i, r := range name {
		switch {
		case r == '_' || r == '$':
			res = append(res, r)
		case (r >= 'a' && r <= 'z') || (r >= 'A' && r <= 'Z'):
			res = append(res, r)
		case r >= '0' && r <= '9' && i > 0:
			res = append(res, r)
		default:
			res = append(res, '_')
		}
	}
